export class RuleConfig {
  id: any;
  sysRuleId: any;
  ruleId: any;
  ruleName: any;
  sourceTranslationId: any;
  targetTranslationId: any;
  validationSystems: any;
  creatorId: any;
  createdTime: any;
  approverId: any;
  approvedTime: any;
  versionNo: any;
  approvedStatus: string;
  approvedEver: string;
  recordStatus: string;
  mdmtValidationSystemData: Array<MultipleValidation>;
  sysRuleDetails: Array<RuleValidation>;
}
export class RuleValidation {
  id: any;
  ruleId: any;
  validationMethod: any;
  validationDetail: any;
}
export class RuleDto {
  msgRule: RuleConfig;
  msgValidation: Array<RuleValidation>;
}
export class MultipleValidation {
  validationSystem: any;
  messageType: any;
  service: any;
  operation: any;
  id: any;
  ruleId: any;
}